36	async function request<T>(
37	  path: string,
38	  options: RequestInit = {},
39	  session?: Session,
40	): Promise<T> {
41	  const headers: Record<string, string> = {
42	    ...(options.headers as Record<string, string>),
43	  };
44	
45	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
46	    headers["Content-Type"] = "application/json";
47	  }
48	
49	  if (session?.agentId) {
50	    headers["X-Bayes-Agent-Id"] = session.agentId;
51	  }
52	
53	  const res = await fetch(`${API_BASE}${path}`, {
54	    ...options,
55	    headers,
56	  });
57	
58	  const body = await res.json();
59	
60	  if (!res.ok) {
61	    const err = body as ApiError;
62	    throw new BayesApiError(
63	      res.status,
64	      err.error?.code ?? "unknown_error",
65	      err.error?.details ?? {},
66	    );
67	  }
68	
69	  return body as T;
70	}
