1	import { QueryClient, QueryClientProvider, type UseQueryResult, type UseMutationResult } from "@tanstack/react-query";
2	import { MemoryRouter } from "react-router-dom";
3	import { SessionProvider } from "@/features/session/context";
4	import { routerFuture } from "@/app/routerFuture";
5	import { render, type RenderOptions } from "@testing-library/react";
6	import type { ReactElement, ReactNode } from "react";
7	import { vi } from "vitest";
8	
9	function createTestQueryClient() {
10	  return new QueryClient({
11	    defaultOptions: {
12	      queries: { retry: false, gcTime: 0 },
13	      mutations: { retry: false },
14	    },
15	  });
16	}
17	
18	function TestProviders({
19	  children,
20	  initialEntries,
21	}: {
22	  children: ReactNode;
23	  initialEntries?: string[];
24	}) {
25	  const qc = createTestQueryClient();
26	  return (
27	    <QueryClientProvider client={qc}>
28	      <SessionProvider>
29	        <MemoryRouter future={routerFuture} initialEntries={initialEntries}>
30	          {children}
31	        </MemoryRouter>
32	      </SessionProvider>
33	    </QueryClientProvider>
34	  );
35	}
36	
37	export function renderWithProviders(
38	  ui: ReactElement,
39	  options?: Omit<RenderOptions, "wrapper"> & { route?: string; initialEntries?: string[] },
40	) {
41	  const { route, initialEntries, ...renderOptions } = options ?? {};
42	
43	  function Wrapper({ children }: { children: ReactNode }) {
44	    return (
45	      <TestProviders initialEntries={initialEntries ?? (route ? [route] : undefined)}>
46	        {children}
47	      </TestProviders>
48	    );
49	  }
50	
51	  return render(ui, { wrapper: Wrapper, ...renderOptions });
52	}
53	
54	export function createMockQueryResult<T>(
55	  overrides?: Partial<UseQueryResult<T, Error>>,
56	): UseQueryResult<T, Error> {
57	  return {
58	    data: undefined,
59	    error: null,
60	    isLoading: false,
61	    isSuccess: false,
62	    isError: false,
63	    isPending: false,
64	    isLoadingError: false,
65	    isRefetchError: false,
66	    status: "pending",
67	    fetchStatus: "idle",
68	    isFetching: false,
69	    isPlaceholderData: false,
70	    isRefetching: false,
71	    isStale: false,
72	    dataUpdatedAt: 0,
73	    errorUpdatedAt: 0,
74	    failureCount: 0,
75	    failureReason: null,
76	    errorUpdateCount: 0,
77	    isFetched: false,
78	    isFetchedAfterMount: false,
79	    isInitialLoading: false,
80	    isPaused: false,
81	    isEnabled: true,
82	    refetch: vi.fn(),
83	    promise: Promise.resolve(undefined as never),
84	    ...overrides,
85	  } as UseQueryResult<T, Error>;
86	}
87	
88	export function createMockMutationResult<TData = unknown, TError = Error, TVariables = unknown, TContext = unknown>(
89	  overrides?: Partial<UseMutationResult<TData, TError, TVariables, TContext>>,
