import { describe, it, expect, vi, beforeEach } from "vitest";
import { screen } from "@testing-library/react";
import { renderWithProviders } from "./helpers";
import { ForceDirectedGraph } from "@/features/graph/ForceDirectedGraph";
import type { MarketSummary, EngineStatsResponse, Market } from "@/lib/api/types";

// ---------------------------------------------------------------------------
// Mocks
// ---------------------------------------------------------------------------

vi.mock("@/lib/query/hooks", () => ({
  useMarkets: vi.fn(),
  useMarket: vi.fn(),
  useEngineStats: vi.fn(),
}));

// Mock D3 modules to avoid simulation side-effects in tests
vi.mock("d3-force", () => {
  const mockSim = {
    force: vi.fn().mockReturnThis(),
    on: vi.fn().mockReturnThis(),
    nodes: vi.fn().mockReturnThis(),
    alpha: vi.fn().mockReturnThis(),
    alphaTarget: vi.fn().mockReturnThis(),
    restart: vi.fn().mockReturnThis(),
    stop: vi.fn(),
  };
  return {
    forceSimulation: vi.fn(() => mockSim),
    forceLink: vi.fn(() => {
      const fl = vi.fn().mockReturnThis() as unknown as Record<string, ReturnType<typeof vi.fn>>;
      fl.id = vi.fn().mockReturnValue(fl);
      fl.distance = vi.fn().mockReturnValue(fl);
      fl.links = vi.fn().mockReturnValue(fl);
      return fl;
    }),
    forceManyBody: vi.fn(() => ({
      strength: vi.fn().mockReturnThis(),
    })),
    forceCenter: vi.fn(),
    forceCollide: vi.fn(),
  };
});

vi.mock("d3-selection", () => ({
  select: vi.fn(() => ({
    call: vi.fn().mockReturnThis(),
    on: vi.fn().mockReturnThis(),
    selectAll: vi.fn(() => ({
      call: vi.fn().mockReturnThis(),
      on: vi.fn().mockReturnThis(),
    })),
  })),
}));

vi.mock("d3-zoom", () => ({
  zoom: vi.fn(() => {
    const z = vi.fn().mockReturnThis() as unknown as Record<string, ReturnType<typeof vi.fn>>;
    z.scaleExtent = vi.fn().mockReturnValue(z);
    z.on = vi.fn().mockReturnValue(z);
    z.transform = "transform";
    return z;
  }),
  zoomIdentity: {},
}));

vi.mock("d3-drag", () => ({
  drag: vi.fn(() => {
    const d = vi.fn().mockReturnThis() as unknown as Record<string, ReturnType<typeof vi.fn>>;
    d.on = vi.fn().mockReturnValue(d);
    return d;
  }),
}));

import { useMarkets, useMarket, useEngineStats } from "@/lib/query/hooks";

const mockUseMarkets = vi.mocked(useMarkets);
const mockUseMarket = vi.mocked(useMarket);
const mockUseEngineStats = vi.mocked(useEngineStats);

// ---------------------------------------------------------------------------
// Fixtures
